buildscript {
    ext.kotlin_version = '1.7.10'
    repositories {
        google()
        mavenCentral()
    }

    dependencies {
        classpath 'com.android.tools.build:gradle:7.3.0'
        classpath "org.jetbrains.kotlin:kotlin-gradle-plugin:$kotlin_version"
    }
}
apply plugin: 'com.android.application'
apply plugin: 'kotlin-android'
apply from: "$flutterRoot/packages/flutter_tools/gradle/flutter.gradle"

android {
    namespace "com.example.task_manager_flutter"  // Adicione esta linha
    compileSdk 34  // Atualize para 34

    defaultConfig {
        applicationId "com.example.task_manager_flutter"  // Use seu applicationId real
        minSdk 21
        targetSdk 34  // Atualize para 34
        versionCode 1
        versionName "1.0"
    }

    signingConfigs {
        release {
            storeFile file("jks.jks")
            storePassword "123Mudar\$"
            keyAlias "key0"
            keyPassword "123Mudar\$"
        }
    }

    buildTypes {
        release {
            signingConfig signingConfigs.release
            minifyEnabled false
            shrinkResources false
        }
        debug {
            signingConfig signingConfigs.debug
        }
    }

    compileOptions {
        sourceCompatibility JavaVersion.VERSION_1_8
        targetCompatibility JavaVersion.VERSION_1_8
    }

    kotlinOptions {
        jvmTarget = '1.8'
    }
}

flutter {
    source '../..'
}
allprojects {
    repositories {
        google()
        mavenCentral()
        }
    }

    rootProject.buildDir = '../build'
subprojects {
    project.buildDir = "${rootProject.buildDir}/${project.name}"
}
subprojects {
    project.evaluationDependsOn(':app')
}

tasks.register("clean", Delete) {
    delete rootProject.buildDir
}
